// Gemini 응답에서 base64 이미지 추출
const response = $input.first().json;
const sceneData = $input.first().json;

// Gemini 이미지 응답 파싱
let base64Image = null;
let mimeType = 'image/png';

try {
  const parts = response.candidates[0].content.parts;
  for (const part of parts) {
    if (part.inlineData) {
      base64Image = part.inlineData.data;
      mimeType = part.inlineData.mimeType || 'image/png';
      break;
    }
  }
} catch(e) {
  throw new Error('Gemini 이미지 파싱 실패: ' + JSON.stringify(response));
}

if (!base64Image) {
  throw new Error('이미지 데이터를 찾을 수 없습니다');
}

return [{
  json: {
    title: $('스크립트 파싱 + 씬 분리').item.json.title,
    concept: $('스크립트 파싱 + 씬 분리').item.json.concept,
    bgm_mood: $('스크립트 파싱 + 씬 분리').item.json.bgm_mood,
    srt_content: $('스크립트 파싱 + 씬 분리').item.json.srt_content,
    scene_number: $('스크립트 파싱 + 씬 분리').item.json.scene_number,
    subtitle: $('스크립트 파싱 + 씬 분리').item.json.subtitle,
    date_str: $('스크립트 파싱 + 씬 분리').item.json.date_str,
    total_scenes: $('스크립트 파싱 + 씬 분리').item.json.total_scenes,
    image_base64: base64Image,
    mime_type: mimeType,
    file_name: `scene_${ $('스크립트 파싱 + 씬 분리').item.json.scene_number }_${ $('스크립트 파싱 + 씬 분리').item.json.date_str }.png`
  },
  binary: {
    image: {
      data: base64Image,
      mimeType: mimeType,
      fileName: `scene_${ $('스크립트 파싱 + 씬 분리').item.json.scene_number }_${ $('스크립트 파싱 + 씬 분리').item.json.date_str }.png`
    }
  }
}];

// BGM 선택 로직 - 분위기 키워드로 매칭
const bgmMood = $('스크립트 파싱 + 씬 분리').first().json.bgm_mood;
const dateStr = $('스크립트 파싱 + 씬 분리').first().json.date_str;
const title = $('스크립트 파싱 + 씬 분리').first().json.title;
const concept = $('스크립트 파싱 + 씬 분리').first().json.concept;

// BGM 풀 (Drive에 미리 저장해둔 파일명 목록)
// ⚠️ 소정님이 Suno에서 만든 BGM 파일명으로 교체해주세요
const bgmPool = {
  lofi: 'bgm_lofi_chill.mp3',
  감성: 'bgm_emotional_warm.mp3',
  따뜻한: 'bgm_warm_cozy.mp3',
  신나는: 'bgm_upbeat_fun.mp3',
  잔잔한: 'bgm_calm_peaceful.mp3',
  default: 'bgm_lofi_chill.mp3'
};

// 키워드 매칭
let selectedBgm = bgmPool.default;
for (const [keyword, filename] of Object.entries(bgmPool)) {
  if (bgmMood && bgmMood.includes(keyword)) {
    selectedBgm = filename;
    break;
  }
}

return [{
  json: {
    date_str: dateStr,
    title: title,
    concept: concept,
    bgm_mood: bgmMood,
    selected_bgm: selectedBgm,
    total_scenes: $('스크립트 파싱 + 씬 분리').first().json.total_scenes
  }
}];

